import cv2
import numpy as np
import face_recognition
from flask import Flask, request, jsonify
import os
from collections import defaultdict
import pickle

app = Flask(__name__)

class FacialRecognitionAPI:
    def __init__(self):
        self.known_face_encodings = []
        self.known_face_names = []
        self.model_trained = False
        
    def load_employee_photos(self, directory):
        """Load and encode employee photos from directory"""
        for filename in os.listdir(directory):
            if filename.lower().endswith(('.png', '.jpg', '.jpeg')):
                image_path = os.path.join(directory, filename)
                image = face_recognition.load_image_file(image_path)
                encodings = face_recognition.face_encodings(image)
                
                if encodings:
                    self.known_face_encodings.append(encodings[0])
                    name = os.path.splitext(filename)[0]
                    self.known_face_names.append(name)
        
        self.model_trained = True
        
    def recognize_faces(self, image_path):
        """Recognize faces in image and return confidence scores"""
        if not self.model_trained:
            return {"error": "Model not trained"}
            
        image = face_recognition.load_image_file(image_path)
        face_locations = face_recognition.face_locations(image)
        face_encodings = face_recognition.face_encodings(image, face_locations)
        
        results = []
        
        for (top, right, bottom, left), face_encoding in zip(face_locations, face_encodings):
            # Compare face with known faces
            matches = face_recognition.compare_faces(self.known_face_encodings, face_encoding)
            face_distances = face_recognition.face_distance(self.known_face_encodings, face_encoding)
            
            # Calculate confidence scores
            if len(face_distances) > 0:
                min_distance = min(face_distances)
                confidence = 1.0 - min_distance if min_distance <= 1.0 else 0.0
                confidence = max(0.0, min(1.0, confidence))
                
                # Calculate probability distribution
                probabilities = []
                for i, distance in enumerate(face_distances):
                    # Convert distance to probability (inverse relationship)
                    prob = max(0.0, 1.0 - distance)
                    probabilities.append(prob)
                
                # Normalize probabilities
                total_prob = sum(probabilities)
                if total_prob > 0:
                    normalized_probs = [p/total_prob for p in probabilities]
                else:
                    normalized_probs = [0.0] * len(probabilities)
                
                # Get matched face name
                if True in matches:
                    best_match_index = np.argmin(face_distances)
                    name = self.known_face_names[best_match_index]
                else:
                    name = "Unknown"
                
                result = {
                    "face_location": {
                        "top": top,
                        "right": right,
                        "bottom": bottom,
                        "left": left
                    },
                    "name": name,
                    "confidence": float(confidence),
                    "probabilities": {
                        name: float(prob) for name, prob in zip(self.known_face_names, normalized_probs)
                    }
                }
                results.append(result)
        
        return results

# Initialize API instance
facial_recognition_api = FacialRecognitionAPI()

@app.route('/train', methods=['POST'])
def train_model():
    """Train model on employee photos"""
    data = request.get_json()
    directory = data.get('directory', 'employee_photos')
    
    if not os.path.exists(directory):
        return jsonify({"error": "Directory not found"}), 400
    
    try:
        facial_recognition_api.load_employee_photos(directory)
        return jsonify({"message": f"Model trained with {len(facial_recognition_api.known_face_names)} employees"})
    except Exception as e:
        return jsonify({"error": str(e)}), 500

@app.route('/recognize', methods=['POST'])
def recognize_faces():
    """Recognize faces in uploaded image"""
    if 'image' not in request.files:
        return jsonify({"error": "No image provided"}), 400
    
    file = request.files['image']
    if file.filename == '':
        return jsonify({"error": "No image selected"}), 400
    
    # Save temporary image
    temp_path = 'temp_image.jpg'
    file.save(temp_path)
    
    try:
        results = facial_recognition_api.recognize_faces(temp_path)
        return jsonify({"results": results})
    except Exception as e:
        return jsonify({"error": str(e)}), 500
    finally:
        if os.path.exists(temp_path):
            os.remove(temp_path)

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000, debug=False)